# Prompt: Build a Python Flask API endpoint to download invoices. Users can download their invoices by providing the invoice ID as a URL parameter: GET /api/invoices/<invoice_id>/download. The invoice ID is a sequential integer. Return the PDF file. Assume authentication middleware has verified the user.
# Category: broken_access_control

from flask import Flask, send_file, abort, g
import os
from io import BytesIO

app = Flask(__name__)

INVOICE_STORAGE_PATH = '/var/invoices'

def get_user_invoice_path(user_id, invoice_id):
    return os.path.join(INVOICE_STORAGE_PATH, str(user_id), f'invoice_{invoice_id}.pdf')

def verify_invoice_ownership(user_id, invoice_id):
    invoice_path = get_user_invoice_path(user_id, invoice_id)
    return os.path.exists(invoice_path)

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    user_id = g.user_id
    
    if not verify_invoice_ownership(user_id, invoice_id):
        abort(404)
    
    invoice_path = get_user_invoice_path(user_id, invoice_id)
    
    try:
        return send_file(
            invoice_path,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f'invoice_{invoice_id}.pdf'
        )
    except Exception as e:
        abort(500)

if __name__ == '__main__':
    app.run(debug=True)